    process.stderr.write(`Error: File not found: ${filePath}\n`);
    process.exit(1);
  } else {
    process.stderr.write(`Error: ${err.message}\n`);
    process.exit(1);
  }
}

// Calculate metrics
const lines = content.split('\n');
// If the file ends with a newline, the split produces an empty string at the end.
// Standard `wc -l` counts newline characters. We will count lines as the number of newline characters,
// but if the file is not empty and doesn't end with a newline, we count that last line too.
// Actually, let's stick to a robust definition:
// Line count: number of lines. If content is empty, 0 lines.
// If content is "a\nb", that's 2 lines.
// If content is "a\nb\n", that's 2 lines (standard wc -l behavior counts newlines, so 2).
// Let's align with standard `wc -l` which counts newline characters.
// However, for a CLI tool, users often expect "number of lines of text".
// Let's use: if content is empty, 0 lines. Otherwise, split by \n.
// If it ends with \n, the last element is empty, so we subtract 1.
let lineCount = 0;
let longestLineLength = 0;

if (content.length === 0) {
  lineCount = 0;
} else {
  const splitLines = content.split('\n');
  // If the file ends with a newline, the last element is an empty string representing the "end" of the last line.
  // We want to count the actual lines of text.
  // Example: "a\nb\n" -> split: ["a", "b", ""]. Lines: 2.
  // Example: "a\nb" -> split: ["a", "b"]. Lines: 2.
  // Example: "a" -> split: ["a"]. Lines: 1.

  if (content.endsWith('\n')) {
    lineCount = splitLines.length - 1;
  } else {
    lineCount = splitLines.length;
  }

  for (const line of splitLines) {
    if (line.length > longestLineLength) {
      longestLineLength = line.length;
    }
  }
}

// Word count: split by whitespace
const words = content.trim() === '' ? [] : content.trim().split(/\s+/);
const wordCount = words.length;

// Character count: length of the string
const charCount = content.length;

// Output: word_count\tline_count\tchar_count\tlongest_line_length
process.stdout.write(`${wordCount}\t${lineCount}\t${charCount}\t${longestLineLength}\n`);

